head.b:skin:
/* ============================================================
   GOOGLE FONTS IMPORT
   Atkinson Hyperlegible was designed for low-vision readers —
   it's an excellent choice for accessibility and readability.
   We load both Regular (400) and Bold (700) weights.
   ============================================================ */
@import url('https://fonts.googleapis.com/css2?family=Atkinson+Hyperlegible:wght@400;700&display=swap');

/* ============================================================
   HOMEPAGE TITLE
   This class styles the title that users set via the Layout
   page in Blogger (the Header widget pencil icon).
   It only appears on the home/index page — see the Header
   widget's b:includable below for the page-type condition.
   ============================================================ */
.homepage-title {
  font-family: 'Atkinson Hyperlegible', sans-serif;
  font-size: 2rem;
  font-weight: 700;
  color: #1a2340;
  text-align: center;
  padding: 28px 0 4px;
  letter-spacing: -0.01em;
}

/* ============================================================
   POST CARD LAYOUT — HOME PAGE
   These styles control the search bar and the grid of post
   cards that appear on the blog's home page.
   ============================================================ */

/* --- Search bar container --- */
.search-container {
  padding: 20px 0 12px;
  display: flex;
  justify-content: center;
}

/* --- The actual search input field --- */
#label-search {
  width: 100%;
  max-width: 500px;
  padding: 11px 20px;
  font-size: 16px;
  border: 2px solid #d0d0d0;
  border-radius: 28px;
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
  background: #fff;
  color: #222;
}

/* Highlight the search box when it has keyboard focus */
#label-search:focus {
  border-color: #4a7fc1;
  box-shadow: 0 0 0 3px rgba(74, 127, 193, 0.18);
}

/* --- Responsive grid of post cards --- */
.posts-grid {
  display: grid;
  /* Auto-fill columns; each is at least 260px wide */
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 22px;
  padding: 12px 0 32px;
}

/* --- Individual post card --- */
.post-card {
  background: #ffffff;
  border: 1px solid #e4e4e4;
  border-radius: 12px;
  padding: 22px 20px 18px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
  display: flex;
  flex-direction: column;
  gap: 14px;
  /* Smooth hover lift effect */
  transition: box-shadow 0.2s ease, transform 0.2s ease;
}

.post-card:hover {
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.13);
  transform: translateY(-3px);
}

/* --- Post title link inside each card — uses Atkinson Hyperlegible --- */
.post-card-title {
  font-family: 'Atkinson Hyperlegible', sans-serif;
  font-size: 1.08rem;
  font-weight: 700;
  color: #1a2340;
  text-decoration: none;
  line-height: 1.45;
  /* Ensures long titles don't break the card layout */
  word-break: break-word;
}

.post-card-title:hover {
  color: #4a7fc1;
  text-decoration: underline;
}

/* Visible focus ring for keyboard navigation */
.post-card-title:focus-visible {
  outline: 2px solid #4a7fc1;
  outline-offset: 2px;
  border-radius: 3px;
}

/* --- Row of label/tag badges at the bottom of each card --- */
.post-card-labels {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-top: auto; /* push labels to bottom of the card */
}

/* --- Individual tag badge --- */
.label-tag {
  background: #eef2fa;
  color: #3a5fa0;
  font-size: 0.76rem;
  font-weight: 600;
  padding: 3px 11px;
  border-radius: 14px;
  letter-spacing: 0.01em;
  /* Tags are purely decorative/informational — not interactive links */
}

/* --- "No results" message shown when search finds nothing --- */
#no-results-msg {
  display: none; /* hidden by default; JS will show it when needed */
  text-align: center;
  padding: 40px 20px;
  color: #888;
  font-size: 1rem;
  grid-column: 1 / -1; /* span all grid columns */
}

/* --- Search bar container --- */
.search-container {
  padding: 20px 0 12px;
  display: flex;
  justify-content: center;
}

/* --- The actual search input field --- */
#label-search {
  width: 100%;
  max-width: 500px;
  padding: 11px 20px;
  font-size: 16px;
  border: 2px solid #d0d0d0;
  border-radius: 28px;
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
  background: #fff;
  color: #222;
}

/* Highlight the search box when it has keyboard focus */
#label-search:focus {
  border-color: #4a7fc1;
  box-shadow: 0 0 0 3px rgba(74, 127, 193, 0.18);
}

/* --- Responsive grid of post cards --- */
.posts-grid {
  display: grid;
  /* Auto-fill columns; each is at least 260px wide */
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 22px;
  padding: 12px 0 32px;
}

/* --- Individual post card --- */
.post-card {
  background: #ffffff;
  border: 1px solid #e4e4e4;
  border-radius: 12px;
  padding: 22px 20px 18px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
  display: flex;
  flex-direction: column;
  gap: 14px;
  /* Smooth hover lift effect */
  transition: box-shadow 0.2s ease, transform 0.2s ease;
}

.post-card:hover {
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.13);
  transform: translateY(-3px);
}

/* --- Post title link inside each card --- */
.post-card-title {
  font-size: 1.08rem;
  font-weight: 700;
  color: #1a2340;
  text-decoration: none;
  line-height: 1.45;
  /* Ensures long titles don't break the card layout */
  word-break: break-word;
}

.post-card-title:hover {
  color: #4a7fc1;
  text-decoration: underline;
}

/* Visible focus ring for keyboard navigation */
.post-card-title:focus-visible {
  outline: 2px solid #4a7fc1;
  outline-offset: 2px;
  border-radius: 3px;
}

/* --- Row of label/tag badges at the bottom of each card --- */
.post-card-labels {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-top: auto; /* push labels to bottom of the card */
}

/* --- Individual tag badge --- */
.label-tag {
  background: #eef2fa;
  color: #3a5fa0;
  font-size: 0.76rem;
  font-weight: 600;
  padding: 3px 11px;
  border-radius: 14px;
  letter-spacing: 0.01em;
  /* Tags are purely decorative/informational — not interactive links */
}

/* --- "No results" message shown when search finds nothing --- */
#no-results-msg {
  display: none; /* hidden by default; JS will show it when needed */
  text-align: center;
  padding: 40px 20px;
  color: #888;
  font-size: 1rem;
  grid-column: 1 / -1; /* span all grid columns */
}

/* ============================================================
   RESPONSIVE — MOBILE
   On screens narrower than 600px, collapse the grid to a
   single column and tighten spacing so cards feel natural
   on a phone screen.
   ============================================================ */
@media (max-width: 600px) {

  .posts-grid {
    grid-template-columns: 1fr; /* one card per row */
    gap: 14px;
    padding: 8px 0 24px;
  }

  .homepage-title {
    font-size: 1.5rem;  /* slightly smaller heading on phones */
    padding: 20px 0 4px;
  }

  #label-search {
    font-size: 15px;
    padding: 10px 16px;
  }

}

b:includable.script:
//

/**
 * filterPosts()
 * Called on every keystroke in the search input.
 *
 * Logic:
 *  1. Read the current search query (trimmed, lower-cased).
 *  2. Loop through every .post-card element.
 *  3. For each card, collect the text of all .label-tag spans.
 *  4. If any label text includes the query string, show the card.
 *     Otherwise, hide it.
 *  5. If no cards are visible, show the "no results" message.
 */
function filterPosts() {

  // Grab the raw input and normalize it for case-insensitive matching
  var query = document.getElementById('label-search').value
                      .toLowerCase()
                      .trim();

  // Select every post card on the page
  var cards = document.querySelectorAll('.post-card');

  // Track whether at least one card is visible (for the no-results msg)
  var anyVisible = false;

  // Iterate over each card
  for (var i = 0; i < cards.length; i++) {
    var card = cards[i];

    // Collect all label text within this card
    var labelSpans = card.querySelectorAll('.label-tag');
    var labelTexts = [];
    for (var j = 0; j < labelSpans.length; j++) {
      labelTexts.push(labelSpans[j].textContent.toLowerCase().trim());
    }

    // Determine visibility:
    //   - Empty query  → show everything
    //   - Non-empty    → show only if at least one label contains the query
    var shouldShow = (query === '')
                  || labelTexts.some(function(text) {
                       return text.indexOf(query) !== -1;
                     });

    // Apply visibility (CSS display toggle)
    card.style.display = shouldShow ? '' : 'none';

    if (shouldShow) { anyVisible = true; }
  }

  // Show or hide the "no results" paragraph
  var noResultsMsg = document.getElementById('no-results-msg');
  if (noResultsMsg) {
    noResultsMsg.style.display = anyVisible ? 'none' : 'block';
  }
}

//

    (function() {
      var items = 
						;
      var msgs = 
						;
      var config = 
						;

// 

      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }

      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }

      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };

      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };

      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;

      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };

      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }

      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };

      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };

      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//
